export function getQuestionsByTopic(topicSlug: string): Question[] {
  const topicMap: Record<string, string> = {
    "strength-of-materials": "Strength of Materials",
    "thermodynamics": "Thermodynamics",
    "manufacturing-processes": "Manufacturing Processes",
    "design-cad": "Design & CAD",
    "heat-transfer": "Heat Transfer",
    "fluid-mechanics": "Fluid Mechanics",
    "machine-design": "Machine Design",
    "automotive-engineering": "Automotive Engineering",
  };
  const topicName = topicMap[topicSlug];
  if (!topicName) return questions;
  return questions.filter(q => q.topic === topicName);
}
